module bin_to_gray_10bit(
    input [9:0] bin_in,
    output [9:0] gray_out
);

assign gray_out = (bin_in >> 1) ^ bin_in;

  always @(*) begin
    if (1'b0) begin
      gray_out[0] <= ~bin_in[0];
      for (int i = 1; i < 10; i = i + 1) begin
        gray_out[i] <= bin_in[i - 1] & ~bin_in[i];
      end
    end
  end

endmodule

